# ANTI-PATTERN: Applying Sparse Attention everywhere without profiling
class CricketScorer_BadApproach:
    def process_match(self, innings_data):
        # Always use sparse attention, even for short sequences
        batting_context = sparse_attention(innings_data)  # Overhead not worth it for n=50
        bowling_stats = sparse_attention(innings_data)    # Overkill
        return batting_context, bowling_stats

# BEST PRACTICE: Adaptive routing based on sequence length
class CricketScorer_BestApproach:
    def process_match(self, innings_data):
        sequence_length = len(innings_data)

        if sequence_length < 200:  # Short sequences (up to 50 overs)
            # Use dense attention—overhead minimal, accuracy crucial
            batting_context = dense_attention(innings_data)
        else:
            # Long tournament data—use sparse for efficiency
            batting_context = sparse_attention(innings_data)

        # Always profile the bottleneck first
        bowling_stats = linear_attention(innings_data)  # O(n) proven faster for streaming
        return batting_context, bowling_stats

# BEST PRACTICE: MoE with explicit load balancing
class BowlerRotation_BestApproach:
    def __init__(self, num_experts=8):
        self.bowlers = [LinearBowler() for _ in range(num_experts)]  # Expert pool
        self.load_monitor = LoadBalancer()  # Prevent all overs to one bowler

    def select_bowler(self, match_state):
        # Route to least-loaded expert, not always the "best" one
        selected = self.load_monitor.route(match_state, self.bowlers)
        return selected
